from __future__ import annotations


def iter_file_chunks(file_obj, chunk_size: int, include_index: bool = False):
    if chunk_size < 1:
        raise ValueError('chunk_size must be positive')
    index = 0
    while True:
        chunk = file_obj.read(chunk_size)
        if not chunk:
            return
        if include_index:
            yield (index, chunk)
        else:
            yield chunk
        index += 1

